steps.value:
let unit = "{{subtotalPrice}}";
let shipping = "{{shippingPrice}}";
let tax = "{{taxPrice}}";
let total = "{{total}}";

if (shipping.includes("Lettermail (untracked)") || shipping === ''){
    shipping = "0.00";
};

unit = unit.replace(",","");
shipping = shipping.replace(",","");
tax = tax.replace(",","");
total = total.replace(",","");

unit = Number(unit.replace("{{Symbol}}",""));
shipping = Number(shipping.replace("{{Symbol}}",""));
if (!{{includeTax}}) {
    tax = Number(tax.replace("{{Symbol}}",""));
} else {
    tax = 0
}
total = Number(total.replace("{{Symbol}}",""));

let total2 = unit+shipping+tax;
total2 = Number(total2.toFixed(2));

return total === total2
